// ── TRANSLATION LOOKUP ────────────────────────────────────────────────
function saT(k){
  var s = SA_STRINGS[saLang] || SA_STRINGS.en;
  return s[k] !== undefined ? s[k] : (SA_STRINGS.en[k] || k);
}

// ── CURRENT LANGUAGE STATE ────────────────────────────────────────────
var saLang = localStorage.getItem('sa_lang') || 'en';

// ── APPLY TRANSLATIONS TO THE CURRENT PAGE ────────────────────────────
function saApply(code){
  saLang = code;
  localStorage.setItem('sa_lang', code);
  // Update button
  var lg = SA_LANGS.find(function(x){return x.c===code;});
  if(lg){
    var f=document.getElementById('sa-flag'), c=document.getElementById('sa-code');
    if(f) f.textContent=lg.f;
    if(c) c.textContent=lg.c.toUpperCase();
  }
  // Update all tagged elements
  // Update both data-t and data-i18n elements (legacy support)
  document.querySelectorAll('[data-t],[data-i18n]').forEach(function(el){
    var k = el.getAttribute('data-t') || el.getAttribute('data-i18n');
    var a = el.getAttribute('data-t-attr');
    if(a) el.setAttribute(a, saT(k));
    else el.innerHTML = saT(k);
  });
  // Sync S.lang and hidden form field with globe selection
  if(typeof S!=='undefined' && lg) S.lang=lg.n;
  var _pfl = document.getElementById('pf-lang');
  if(_pfl && lg) _pfl.value = lg.n;
  saLangClose();
  // Re-render pricing page if visible
  if(typeof renderPricingPage === 'function') {
    renderPricingPage();
    // Re-apply translations to any newly rendered data-t elements
    setTimeout(function(){
      document.querySelectorAll('[data-t],[data-i18n]').forEach(function(el){
        var k = el.getAttribute('data-t') || el.getAttribute('data-i18n');
        var a = el.getAttribute('data-t-attr');
        var v = saT(k);
        if(a) el.setAttribute(a, v);
        else if(v && v !== k) el.innerHTML = v;
      });
    }, 50);
  }
}

// ── LANGUAGE PICKER UI ────────────────────────────────────────────────
function saLangToggle(e){
  if(e){e.stopPropagation();e.preventDefault();}
  var p=document.getElementById('sa-lang-panel');
  if(!p){alert('Language panel not found!');return;}
  var open = p.style.display==='block';
  if(open){
    p.style.display='none';
  } else {
    saLangRender(SA_LANGS);
    p.style.display='block';
    var s=document.getElementById('sa-lang-search');
    if(s){s.value='';setTimeout(function(){s.focus();},50);}
  }
}

function saLangClose(){
  var p=document.getElementById('sa-lang-panel');
  if(p) p.style.display='none';
}

function saLangFilter(val){
  var q=val.toLowerCase();
  var filtered = q ? SA_LANGS.filter(function(l){
    return l.n.toLowerCase().includes(q)||l.nat.toLowerCase().includes(q)||l.c.includes(q);
  }) : SA_LANGS;
  saLangRender(filtered);
}

function saLangRender(list){
  var el=document.getElementById('sa-lang-list');
  if(!el) return;
  el.innerHTML='';
  list.forEach(function(lg){
    var d=document.createElement('div');
    d.className='sa-lang-item'+(lg.c===saLang?' active':'');
    d.innerHTML='<span class="lf">'+lg.f+'</span><span class="ln">'+lg.n+'</span><span class="lnat">'+lg.nat+'</span>';
    d.onclick=function(){saApply(lg.c);};
    el.appendChild(d);
  });
}
